// ---- MVVM in Practice ----

// ---- Full MVVM Implementation ----

// ---- Model ----
// Domain layer (pure Kotlin)
data class Task(
    val id: Int,
    val title: String,
    val description: String,
    val isCompleted: Boolean = false,
    val priority: Priority = Priority.MEDIUM,
    val createdAt: Long = System.currentTimeMillis()
)

enum class Priority { LOW, MEDIUM, HIGH }

// ---- Repository ----
interface TaskRepository {
    suspend fun getTasks(): List<Task>
    suspend fun getTask(id: Int): Task?
    suspend fun saveTask(task: Task)
    suspend fun deleteTask(id: Int)
    suspend fun toggleComplete(id: Int)
}

class TaskRepositoryImpl : TaskRepository {
    private val _tasks = mutableListOf<Task>()
    private var nextId = 1

    override suspend fun getTasks(): List<Task> {
        return _tasks
    }

    override suspend fun getTask(id: Int): Task? {
        return _tasks.find { it.id == id }
    }

    override suspend fun saveTask(task: Task) {
        val newTask = if (task.id == 0) {
            task.copy(id = nextId++)
        } else {
            task
        }
        val index = _tasks.indexOfFirst { it.id == newTask.id }
        if (index != -1) {
            _tasks[index] = newTask
        } else {
            _tasks.add(newTask)
        }
    }

    override suspend fun deleteTask(id: Int) {
        _tasks.removeAll { it.id == id }
    }

    override suspend fun toggleComplete(id: Int) {
        val task = _tasks.find { it.id == id } ?: return
        _tasks[_tasks.indexOf(task)] = task.copy(isCompleted = !task.isCompleted)
    }
}

// ---- Use Cases ----
class GetTasksUseCase(
    private val repository: TaskRepository
) {
    suspend operator fun invoke(): List<Task> = repository.getTasks()
}

class GetTaskUseCase(
    private val repository: TaskRepository
) {
    suspend operator fun invoke(id: Int): Task? = repository.getTask(id)
}

class SaveTaskUseCase(
    private val repository: TaskRepository
) {
    suspend operator fun invoke(task: Task) = repository.saveTask(task)
}

class DeleteTaskUseCase(
    private val repository: TaskRepository
) {
    suspend operator fun invoke(id: Int) = repository.deleteTask(id)
}

class ToggleCompleteUseCase(
    private val repository: TaskRepository
) {
    suspend operator fun invoke(id: Int) = repository.toggleComplete(id)
}

class FilterTasksUseCase {
    operator fun invoke(tasks: List<Task>, filter: TaskFilter): List<Task> {
        return when (filter) {
            TaskFilter.ALL -> tasks
            TaskFilter.ACTIVE -> tasks.filter { !it.isCompleted }
            TaskFilter.COMPLETED -> tasks.filter { it.isCompleted }
            TaskFilter.HIGH_PRIORITY -> tasks.filter { it.priority == Priority.HIGH }
        }
    }
}

enum class TaskFilter { ALL, ACTIVE, COMPLETED, HIGH_PRIORITY }

// ---- ViewModel ----
class TaskViewModel(
    private val getTasks: GetTasksUseCase,
    private val getTask: GetTaskUseCase,
    private val saveTask: SaveTaskUseCase,
    private val deleteTask: DeleteTaskUseCase,
    private val toggleComplete: ToggleCompleteUseCase,
    private val filterTasks: FilterTasksUseCase
) : ViewModel() {

    data class TaskUiState(
        val tasks: List<Task> = emptyList(),
        val filteredTasks: List<Task> = emptyList(),
        val selectedTask: Task? = null,
        val filter: TaskFilter = TaskFilter.ALL,
        val isLoading: Boolean = false,
        val error: String? = null,
        val isEditing: Boolean = false,
        val editedTask: Task? = null
    )

    private val _uiState = MutableStateFlow(TaskUiState())
    val uiState: StateFlow<TaskUiState> = _uiState.asStateFlow()

    init {
        loadTasks()
    }

    fun loadTasks() {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }
            try {
                val tasks = getTasks()
                _uiState.update {
                    it.copy(
                        tasks = tasks,
                        filteredTasks = filterTasks(tasks, it.filter),
                        isLoading = false
                    )
                }
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun setFilter(filter: TaskFilter) {
        _uiState.update { state ->
            state.copy(
                filter = filter,
                filteredTasks = filterTasks(state.tasks, filter)
            )
        }
    }

    fun selectTask(id: Int) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }
            try {
                val task = getTask(id)
                _uiState.update {
                    it.copy(selectedTask = task, isLoading = false)
                }
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun startEdit() {
        val task = _uiState.value.selectedTask
        if (task != null) {
            _uiState.update {
                it.copy(isEditing = true, editedTask = task)
            }
        }
    }

    fun cancelEdit() {
        _uiState.update {
            it.copy(isEditing = false, editedTask = null)
        }
    }

    fun updateEditedTask(title: String, description: String, priority: Priority) {
        val task = _uiState.value.editedTask
        if (task != null) {
            _uiState.update {
                it.copy(
                    editedTask = task.copy(
                        title = title,
                        description = description,
                        priority = priority
                    )
                )
            }
        }
    }

    fun saveEditedTask() {
        val task = _uiState.value.editedTask ?: return
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }
            try {
                saveTask(task)
                loadTasks()
                _uiState.update {
                    it.copy(
                        isEditing = false,
                        editedTask = null,
                        selectedTask = task,
                        isLoading = false
                    )
                }
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun addTask(title: String, description: String, priority: Priority) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }
            try {
                val task = Task(
                    id = 0,
                    title = title,
                    description = description,
                    priority = priority
                )
                saveTask(task)
                loadTasks()
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun toggleTaskComplete(id: Int) {
        viewModelScope.launch {
            try {
                toggleComplete(id)
                loadTasks()
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message)
                }
            }
        }
    }

    fun deleteTask(id: Int) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }
            try {
                deleteTask(id)
                _uiState.update { it.copy(selectedTask = null) }
                loadTasks()
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun clearError() {
        _uiState.update { it.copy(error = null) }
    }
}

// ---- UI ----
@Composable
fun MVVMScreen() {
    val viewModel: TaskViewModel = viewModel(factory = TaskViewModelFactory())
    val uiState by viewModel.uiState.collectAsState()

    var showAddDialog by remember { mutableStateOf(false) }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Tasks") },
                actions = {
                    IconButton(onClick = { viewModel.loadTasks() }) {
                        Icon(Icons.Default.Refresh, null)
                    }
                    IconButton(onClick = { showAddDialog = true }) {
                        Icon(Icons.Default.Add, null)
                    }
                }
            )
        }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(16.dp)
        ) {
            // ---- Filter chips ----
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                TaskFilter.values().forEach { filter ->
                    FilterChip(
                        selected = uiState.filter == filter,
                        onClick = { viewModel.setFilter(filter) },
                        label = { Text(filter.name) }
                    )
                }
            }

            Spacer(modifier = Modifier.height(8.dp))

            if (uiState.isLoading) {
                Box(modifier = Modifier.fillMaxWidth().height(50.dp), contentAlignment = Alignment.Center) {
                    CircularProgressIndicator()
                }
            }

            if (uiState.error != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.errorContainer
                    )
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Text(uiState.error ?: "", color = MaterialTheme.colorScheme.onErrorContainer)
                        Button(onClick = { viewModel.clearError() }) { Text("Dismiss") }
                    }
                }
            }

            // ---- Selected task ----
            if (uiState.selectedTask != null && !uiState.isEditing) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    elevation = CardDefaults.cardElevation(4.dp)
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Text(
                            text = uiState.selectedTask?.title ?: "",
                            style = MaterialTheme.typography.titleLarge
                        )
                        Text(
                            text = uiState.selectedTask?.description ?: "",
                            style = MaterialTheme.typography.bodyMedium
                        )
                        Text(
                            text = "Priority: ${uiState.selectedTask?.priority}",
                            style = MaterialTheme.typography.bodySmall
                        )
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            Button(
                                onClick = { viewModel.startEdit() },
                                modifier = Modifier.weight(1f)
                            ) { Text("Edit") }
                            Button(
                                onClick = { viewModel.toggleTaskComplete(uiState.selectedTask?.id ?: 0) },
                                modifier = Modifier.weight(1f)
                            ) {
                                Text(if (uiState.selectedTask?.isCompleted == true) "Reopen" else "Complete")
                            }
                            Button(
                                onClick = { viewModel.deleteTask(uiState.selectedTask?.id ?: 0) },
                                modifier = Modifier.weight(1f),
                                colors = ButtonDefaults.buttonColors(
                                    containerColor = MaterialTheme.colorScheme.error
                                )
                            ) { Text("Delete") }
                        }
                    }
                }
            }

            // ---- Edit dialog ----
            if (uiState.isEditing) {
                EditTaskDialog(
                    task = uiState.editedTask,
                    onUpdate = { title, description, priority ->
                        viewModel.updateEditedTask(title, description, priority)
                    },
                    onSave = { viewModel.saveEditedTask() },
                    onCancel = { viewModel.cancelEdit() }
                )
            }

            // ---- Tasks list ----
            LazyColumn(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                items(uiState.filteredTasks) { task ->
                    TaskItem(
                        task = task,
                        onClick = { viewModel.selectTask(task.id) },
                        onToggleComplete = { viewModel.toggleTaskComplete(task.id) }
                    )
                }
            }

            Text(
                text = "${uiState.filteredTasks.size} tasks",
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant
            )
        }
    }

    if (showAddDialog) {
        AddTaskDialog(
            onDismiss = { showAddDialog = false },
            onAdd = { title, description, priority ->
                viewModel.addTask(title, description, priority)
                showAddDialog = false
            }
        )
    }
}

@Composable
fun TaskItem(
    task: Task,
    onClick: () -> Unit,
    onToggleComplete: () -> Unit
) {
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .clickable { onClick() },
        elevation = CardDefaults.cardElevation(2.dp)
    ) {
        Row(
            modifier = Modifier.fillMaxWidth().padding(8.dp),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column {
                Text(
                    text = task.title,
                    style = MaterialTheme.typography.titleMedium,
                    color = if (task.isCompleted) MaterialTheme.colorScheme.onSurfaceVariant else MaterialTheme.colorScheme.onSurface
                )
                Text(
                    text = task.description,
                    style = MaterialTheme.typography.bodySmall,
                    maxLines = 1,
                    overflow = TextOverflow.Ellipsis
                )
            }

            Row(verticalAlignment = Alignment.CenterVertically) {
                // Priority indicator
                Box(
                    modifier = Modifier
                        .size(10.dp)
                        .background(
                            when (task.priority) {
                                Priority.HIGH -> Color.Red
                                Priority.MEDIUM -> Color.Yellow
                                Priority.LOW -> Color.Green
                            },
                            CircleShape
                        )
                )
                Spacer(modifier = Modifier.width(8.dp))

                Checkbox(
                    checked = task.isCompleted,
                    onCheckedChange = { onToggleComplete() }
                )
            }
        }
    }
}

@Composable
fun AddTaskDialog(
    onDismiss: () -> Unit,
    onAdd: (String, String, Priority) -> Unit
) {
    var title by remember { mutableStateOf("") }
    var description by remember { mutableStateOf("") }
    var priority by remember { mutableStateOf(Priority.MEDIUM) }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text("Add Task") },
        text = {
            Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                OutlinedTextField(
                    value = title,
                    onValueChange = { title = it },
                    label = { Text("Title") },
                    modifier = Modifier.fillMaxWidth()
                )
                OutlinedTextField(
                    value = description,
                    onValueChange = { description = it },
                    label = { Text("Description") },
                    modifier = Modifier.fillMaxWidth()
                )

                Text("Priority:", style = MaterialTheme.typography.labelMedium)
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    Priority.values().forEach { p ->
                        FilterChip(
                            selected = priority == p,
                            onClick = { priority = p },
                            label = { Text(p.name) }
                        )
                    }
                }
            }
        },
        confirmButton = {
            TextButton(
                onClick = { onAdd(title, description, priority) },
                enabled = title.isNotBlank()
            ) { Text("Add") }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) { Text("Cancel") }
        }
    )
}

@Composable
fun EditTaskDialog(
    task: Task?,
    onUpdate: (String, String, Priority) -> Unit,
    onSave: () -> Unit,
    onCancel: () -> Unit
) {
    if (task == null) return

    var title by remember { mutableStateOf(task.title) }
    var description by remember { mutableStateOf(task.description) }
    var priority by remember { mutableStateOf(task.priority) }

    AlertDialog(
        onDismissRequest = onCancel,
        title = { Text("Edit Task") },
        text = {
            Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                OutlinedTextField(
                    value = title,
                    onValueChange = { title = it; onUpdate(it, description, priority) },
                    label = { Text("Title") },
                    modifier = Modifier.fillMaxWidth()
                )
                OutlinedTextField(
                    value = description,
                    onValueChange = { description = it; onUpdate(title, it, priority) },
                    label = { Text("Description") },
                    modifier = Modifier.fillMaxWidth()
                )

                Text("Priority:", style = MaterialTheme.typography.labelMedium)
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    Priority.values().forEach { p ->
                        FilterChip(
                            selected = priority == p,
                            onClick = { priority = p; onUpdate(title, description, p) },
                            label = { Text(p.name) }
                        )
                    }
                }
            }
        },
        confirmButton = {
            TextButton(
                onClick = onSave,
                enabled = title.isNotBlank()
            ) { Text("Save") }
        },
        dismissButton = {
            TextButton(onClick = onCancel) { Text("Cancel") }
        }
    )
}

class TaskViewModelFactory : ViewModelProvider.Factory {
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        if (modelClass.isAssignableFrom(TaskViewModel::class.java)) {
            @Suppress("UNCHECKED_CAST")
            val repository = TaskRepositoryImpl()
            return TaskViewModel(
                GetTasksUseCase(repository),
                GetTaskUseCase(repository),
                SaveTaskUseCase(repository),
                DeleteTaskUseCase(repository),
                ToggleCompleteUseCase(repository),
                FilterTasksUseCase()
            ) as T
        }
        throw IllegalArgumentException("Unknown ViewModel class")
    }
}

