class BrokenMVVM {
    // 1. ViewModel with Android dependencies
    class BadViewModel(context: Context) : ViewModel()

    // 2. UI logic in ViewModel
    class BadViewModel2 : ViewModel() {
        fun formatDate(date: Long): String {
            // Formatting logic in ViewModel
            return SimpleDateFormat("dd/MM/yyyy").format(Date(date))
        }
    }

    // 3. ViewModel exposing mutable state
    class BadViewModel3 : ViewModel() {
        val state = MutableStateFlow("data") // Should be private
    }

    // 4. No unidirectional flow
    // 5. No use cases
    // 6. No repository
}

phase2.explanation:
🤖 **Common MVVM mistakes and fixes.**

| Mistake | Fix |
|---------|-----|
| Android in ViewModel | Keep ViewModel pure |
| UI logic in ViewModel | Use Use Cases |
| Exposed mutable state | Expose immutable |
| No unidirectional flow | Single direction |
| No use cases | Use Use Cases |

**Fixes:**
```kotlin
// 1. No Android dependencies
class GoodViewModel : ViewModel()

// 2. UI logic in View
// Format in Composable, not ViewModel

// 3. Expose immutable
private val _state = MutableStateFlow("data")
val state: StateFlow<String> = _state.asStateFlow()

// 4. Unidirectional flow
// Event → ViewModel → State → UI

// 5. Use Use Cases
class GetDataUseCase

// 6. Use Repository
interface Repository
```
